#!/usr/bin/env python3
from z3 import BitVec, BitVecVal, Concat, Extract, RotateLeft, Solver, sat

MASK32 = 0xFFFFFFFF


def left32(x):
    return (x >> 32) & MASK32


def right32(x):
    return x & MASK32


def expand(seed):
    return (seed ^ ((seed << 16) & MASK32) ^ ((seed * 12345) & MASK32)) & MASK32


def g_function(a, b, x):
    temp = (a + b + x) & 0xFF
    return ((temp << 2) | (temp >> 6)) & 0xFF


def f_function(value):
    x = [(value >> (8 * i)) & 0xFF for i in range(4)]
    y = [0] * 4
    y[2] = g_function(x[3] ^ x[2], x[1] ^ x[0], 1)
    y[3] = g_function(x[3], y[2], 0)
    y[1] = g_function(x[1] ^ x[0], y[2], 0)
    y[0] = g_function(x[0], y[1], 1)
    return sum(y[i] << (8 * i) for i in range(4)) & MASK32


def encrypt(plaintext, seeds):
    keys = [expand(seed) for seed in seeds]
    left = left32(plaintext)
    right = right32(plaintext) ^ left
    for key in keys:
        left, right = right, left ^ f_function(right ^ key)
    left ^= right
    return ((right & MASK32) << 32) | (left & MASK32)


def decrypt(ciphertext, seeds):
    keys = [expand(seed) for seed in seeds]
    left = right32(ciphertext)
    right = left32(ciphertext)
    left ^= right
    for key in reversed(keys):
        temp = left
        left = right ^ f_function(temp ^ key)
        right = temp
    right ^= left
    return ((left & MASK32) << 32) | (right & MASK32)


def z3_f(value):
    x0 = Extract(7, 0, value)
    x1 = Extract(15, 8, value)
    x2 = Extract(23, 16, value)
    x3 = Extract(31, 24, value)

    def z3_g(a, b, x):
        return RotateLeft(a + b + BitVecVal(x, 8), 2)

    y2 = z3_g(x3 ^ x2, x1 ^ x0, 1)
    y3 = z3_g(x3, y2, 0)
    y1 = z3_g(x1 ^ x0, y2, 0)
    y0 = z3_g(x0, y1, 1)
    return Concat(y3, y2, y1, y0)


def z3_expand(seed):
    return seed ^ (seed << 16) ^ (seed * BitVecVal(12345, 32))


def z3_encrypt_halves(plaintext, keys):
    left = BitVecVal(left32(plaintext), 32)
    right = BitVecVal(right32(plaintext), 32) ^ left
    for key in keys:
        left, right = right, left ^ z3_f(right ^ key)
    left ^= right
    return right, left


def read_pairs(path):
    with open(path) as f:
        return [tuple(map(int, line.split())) for line in f if line.strip()]


def recover_seeds(pairs):
    solver = Solver()
    seeds = [BitVec(f"seed{i}", 32) for i in range(4)]
    for seed in seeds:
        solver.add(Extract(31, 20, seed) == 0)
    keys = [z3_expand(seed) for seed in seeds]

    for plaintext, ciphertext in pairs:
        cipher_left, cipher_right = left32(ciphertext), right32(ciphertext)
        enc_left, enc_right = z3_encrypt_halves(plaintext, keys)
        solver.add(enc_left == BitVecVal(cipher_left, 32))
        solver.add(enc_right == BitVecVal(cipher_right, 32))

    if solver.check() != sat:
        raise RuntimeError("known plaintext constraints are unsatisfiable")
    model = solver.model()
    return [model.eval(seed).as_long() for seed in seeds]


def main():
    pairs = read_pairs("/app/pairs.txt")
    seeds = recover_seeds(pairs[:2])
    if any(encrypt(plaintext, seeds) != ciphertext for plaintext, ciphertext in pairs):
        raise RuntimeError("recovered seeds failed full known-pair verification")

    with open("/app/ciphertexts.txt") as in_file, open("/app/plaintexts.txt", "w") as out_file:
        for line in in_file:
            if line.strip():
                out_file.write(f"{decrypt(int(line), seeds)}\n")

    print("Recovered seeds:", " ".join(f"{seed:05x}" for seed in seeds))
    print(f"Verified {len(pairs)} known plaintext/ciphertext pairs")
    print("Wrote /app/plaintexts.txt")


if __name__ == "__main__":
    main()
